import { NextResponse } from 'next/server';

type Params = Promise<{ id: string }>;

export async function GET(_: Request, { params }: { params: Params }) {
  const { id } = await params;
  const post = {
    id: Number.parseInt(id, 10),
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(post);
}

export async function PUT(request: Request, { params }: { params: Params }) {
  const { id } = await params;
  const body: { title?: string; content?: string } = await request.json();
  const { title, content } = body;

  const updatedPost = {
    id: Number.parseInt(id, 10),
    title: title || `Post ${id}`,
    content: content || `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  return NextResponse.json(updatedPost);
}

export async function DELETE(_: Request, { params }: { params: Params }) {
  const { id } = await params;
  return NextResponse.json({ message: `Post ${id} deleted successfully` });
}
